import Foundation
import SwiftUI
import WidgetKit

/// Renders the layout matching the active widget family, resolving to the "default"
/// layout when no per-family override was published.
struct CN1WidgetEntryView: View {
    let entry: CN1WidgetEntry
    @Environment(\.widgetFamily) var family

    var body: some View {
        let layout = cn1LayoutForFamily(entry.layouts, family: family)
        return Group {
            if let layout = layout {
                cn1RenderNode(layout, CN1RenderContext(
                        state: entry.state,
                        imagesDir: entry.imagesDir,
                        source: entry.kind,
                        allowLinks: cn1FamilyAllowsLinks(family),
                        parentAxis: nil))
            } else {
                // Placeholder shown before the app publishes its first timeline.
                Text("No data yet")
                        .font(.system(size: 12))
                        .foregroundColor(.secondary)
            }
        }
        // The root action fires on families where per-node Links are unsupported
        // (small widgets, lock screen accessories) and as the default tap elsewhere.
        .widgetURL(cn1RootActionURL(layout, source: entry.kind))
        .cn1WidgetContainerBackground()
    }
}

func cn1LayoutForFamily(_ layouts: [String: Any], family: WidgetFamily) -> [String: Any]? {
    let key: String
    switch family {
    case .systemSmall:
        key = "small"
    case .systemMedium:
        key = "medium"
    case .systemLarge, .systemExtraLarge:
        key = "large"
    case .accessoryRectangular:
        key = "lockscreen"
    default:
        key = "default"
    }
    if let layout = layouts[key] as? [String: Any] {
        return layout
    }
    return layouts["default"] as? [String: Any]
}

/// Per-node Link actions only work on medium and larger home-screen families; everywhere
/// else the tap target is the whole widget via widgetURL.
func cn1FamilyAllowsLinks(_ family: WidgetFamily) -> Bool {
    switch family {
    case .systemMedium, .systemLarge, .systemExtraLarge:
        return true
    default:
        return false
    }
}

extension View {
    /// iOS 17 requires widgets to declare a container background (or show a scolding
    /// placeholder). The surfaces node tree draws its own backgrounds, so declare a
    /// clear one; earlier versions pass through unchanged.
    @ViewBuilder func cn1WidgetContainerBackground() -> some View {
        if #available(iOS 17.0, *) {
            self.containerBackground(for: .widget) {
                Color.clear
            }
        } else {
            self
        }
    }
}

/// Shared factory behind every generated CN1Widget_<kindid> struct.
func cn1MakeWidgetConfiguration(kind: String, displayName: String, description desc: String,
        families: [WidgetFamily]) -> some WidgetConfiguration {
    return StaticConfiguration(kind: kind, provider: CN1WidgetProvider(kind: kind)) { entry in
        CN1WidgetEntryView(entry: entry)
